import React from 'react'
import { StaticQuery, graphql } from 'gatsby'
import profilePic from './profile-pic.jpg'

import { rhythm } from '../utils/typography'

function Bio() {
  return (
    <StaticQuery
      query={bioQuery}
      render={data => {
        const { author, twitter, github } = data.site.siteMetadata
        return (
          <div
            style={{
              display: `flex`,
              marginBottom: rhythm(2.5),
            }}
          >
            <img
              src={profilePic}
              alt={author}
              style={{
                marginRight: rhythm(1 / 2),
                marginBottom: 0,
                width: rhythm(2),
                height: rhythm(2),
                borderRadius: '30%',
              }}
            />
            <aside>
              Hi, I'm Jan 👋 I am a frontend engineer working for{' '}
              <ExternalLink href="https://soundcloud.com">
                SoundCloud
              </ExternalLink>{' '}
              in Berlin. On this page I publish my frontend-related posts and
              talks.
              <br />
              Find me on{' '}
              <ExternalLink href={`https://twitter.com/${twitter}`}>
                🐦 Twitter
              </ExternalLink>{' '}
              or{' '}
              <ExternalLink href={`https://github.com/${github}`}>
                💻 Github
              </ExternalLink>
              .
            </aside>
          </div>
        )
      }}
    />
  )
}
import ExternalLink from './ExternalLink'

export default Bio

const bioQuery = graphql`
  query BioQuery {
    avatar: file(absolutePath: { regex: "/profile-pic.jpg/" }) {
      childImageSharp {
        fixed(width: 50, height: 50) {
          ...GatsbyImageSharpFixed
        }
      }
    }
    site {
      siteMetadata {
        author
        twitter
        github
      }
    }
  }
`
